import React, { useState, useEffect } from "react";
import { Link, useLocation, useNavigate } from "react-router-dom";
import "./Menu.css";

const Menu = () => {
  const location = useLocation();
  const navigate = useNavigate();

  const [isOpen, setIsOpen] = useState(false);
  const [mode, setMode] = useState("login");

  const [user, setUser] = useState(null);

  const [isErrorOpen, setIsErrorOpen] = useState(false);
  const [errorMessage, setErrorMessage] = useState("");

  const [formData, setFormData] = useState({
    email: "",
    password: "",
    role: "organizer"
  });

  const items = [
    { name: "Головна", path: "/" },
    { name: "Події", path: "/events" },
    { name: "Новини", path: "/news" },
    { name: "Про нас", path: "/about" }
  ];

  // 🔥 загрузка пользователя
  useEffect(() => {
    const storedUser = JSON.parse(localStorage.getItem("user"));
    if (storedUser) setUser(storedUser);
  }, []);

  // 🔥 РЕГИСТРАЦИЯ
  const handleRegister = async () => {
    try {
      const res = await fetch("http://localhost:5000/auth/register", {
        method: "POST",
        headers: {
          "Content-Type": "application/json"
        },
        body: JSON.stringify(formData)
      });

      const data = await res.json();

      if (!res.ok) {
        setErrorMessage(data.error);
        setIsErrorOpen(true);
        return;
      }

      alert("Реєстрація успішна 🎉");
      setMode("login");

    } catch (err) {
      console.error(err);
      setErrorMessage("Помилка сервера");
      setIsErrorOpen(true);
    }
  };

  // 🔥 ЛОГИН
  const handleLogin = async () => {
    try {
      const res = await fetch("http://localhost:5000/auth/login", {
        method: "POST",
        headers: {
          "Content-Type": "application/json"
        },
        body: JSON.stringify({
          email: formData.email,
          password: formData.password
        })
      });

      const data = await res.json();

      if (!res.ok) {
        setErrorMessage(data.error);
        setIsErrorOpen(true);
        return;
      }

      localStorage.setItem("user", JSON.stringify(data.user));
      setUser(data.user);

      setIsOpen(false);

      // 🔥 редирект
      if (data.user.role === "admin") {
        navigate("/admin");
      } else {
        navigate("/dashboard");
      }

    } catch (err) {
      console.error(err);
      setErrorMessage("Помилка сервера");
      setIsErrorOpen(true);
    }
  };

  // 🔥 SUBMIT
  const handleSubmit = (e) => {
    e.preventDefault();

    if (!formData.email || !formData.password) {
      setErrorMessage("Заповни всі поля");
      setIsErrorOpen(true);
      return;
    }

    if (mode === "login") {
      handleLogin();
    } else {
      handleRegister();
    }
  };

  // 🔥 ВЫХОД
  const logout = () => {
    localStorage.removeItem("user");
    setUser(null);
    navigate("/");
  };

  return (
    <>
      <nav className="menu">
        <div className="menu-inner">

          <div className="logo">
            <Link to="/">SkillMeet</Link>
          </div>

          <ul>
            {items.map((item) => (
              <li key={item.name}>
                <Link
                  to={item.path}
                  className={location.pathname === item.path ? "active" : ""}
                >
                  {item.name}
                </Link>
              </li>
            ))}
          </ul>

          {!user ? (
            <button className="login-btn" onClick={() => setIsOpen(true)}>
              Увійти
            </button>
          ) : (
            <div className="user-block">
              <span className="user-email">
                {user.email} ({user.role})
              </span>

              <button className="logout-btn" onClick={logout}>
                Вийти
              </button>
            </div>
          )}

        </div>
      </nav>

      {/* 🔥 МОДАЛКА */}
      {isOpen && (
        <div className="modal-overlay" onClick={() => setIsOpen(false)}>
          <div className="modal" onClick={(e) => e.stopPropagation()}>

            <h2>{mode === "login" ? "Вхід" : "Реєстрація"}</h2>

            <form onSubmit={handleSubmit}>

              <input
                type="email"
                autoComplete="nope"
                placeholder="Email"
                value={formData.email}
                onChange={(e) =>
                  setFormData({ ...formData, email: e.target.value })
                }
              />

              <input
                type="password"
                autoComplete="nope"
                placeholder="Пароль"
                value={formData.password}
                onChange={(e) =>
                  setFormData({ ...formData, password: e.target.value })
                }
              />

              {mode === "register" && (
                <select
                  value={formData.role}
                  onChange={(e) =>
                    setFormData({ ...formData, role: e.target.value })
                  }
                >
                  <option value="organizer">Організатор</option>
                  <option value="admin">Адміністратор</option>
                </select>
              )}

              <button type="submit">
                {mode === "login" ? "Увійти" : "Зареєструватися"}
              </button>
            </form>

            <p className="switch-mode">
              {mode === "login"
                ? "Немає акаунта?"
                : "Вже є акаунт?"}

              <span
                onClick={() =>
                  setMode(mode === "login" ? "register" : "login")
                }
              >
                {mode === "login" ? " Реєстрація" : " Увійти"}
              </span>
            </p>

            <button className="close-btn" onClick={() => setIsOpen(false)}>
              Закрити
            </button>

          </div>
        </div>
      )}

      {/* ❌ МОДАЛКА ПОМИЛКИ */}
      {isErrorOpen && (
        <div className="modal-overlay" onClick={() => setIsErrorOpen(false)}>
          <div
            className="modal error-modal"
            onClick={(e) => e.stopPropagation()}
          >
            <h2>Помилка ❌</h2>
            <p>{errorMessage}</p>

            <button
              className="close-btn"
              onClick={() => setIsErrorOpen(false)}
            >
              Закрити
            </button>
          </div>
        </div>
      )}
    </>
  );
};

export default Menu;
